using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2. TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Demonstrate the "not available" path using a resolver that only handles Person
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (limited.TryGetTypeInfo<int>(out JsonTypeInfo<int>? intInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int> succeeded: {intInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int> returned false — metadata not available");
}

public record Person(string Name, int Age);

/// <summary>A resolver that only provides metadata for Person.</summary>
file class PersonOnlyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return JsonMetadataServices.CreateObjectInfo<Person>(options,
                new JsonObjectInfoValues<Person>());

        return null; // signal "not available"
    }
}
